Content.Interface:
PROGRAM RTPP_PROGRAM
// ============================================================
// GENERIC SITE WRAPPER TEMPLATE
// Keep this file as the site adapter layer:
//   1) Map local site tags to FrontPOA/RearPOA/BOMTemp arrays
//   2) Set plant constants in VAR CONSTANT
//   3) Call the generic FB_RTPP block
// Generic library blocks (FB_RTPP, FB_RTPP_CALC, RTPP_REG,
// FB_SENSOR_AVG, UDT_SENSOR) should remain unchanged.
// ============================================================
VAR
	RTPP : FB_RTPP; // One instance of the generic FB per plant

	// Sensor arrays populated from site tags
	FrontPOA : ARRAY[1..30] OF UDT_SENSOR;
	RearPOA  : ARRAY[1..30] OF UDT_SENSOR;
	BOMTemp  : ARRAY[1..30] OF UDT_SENSOR;
END_VAR

VAR CONSTANT
	// Plant constants: change these per site
	PLANT_TOTAL_INVERTERS : REAL := 47.0;
	PLANT_DC_NOMINAL_MW   : REAL := 236.113;
	PLANT_COMM_YEAR       : DINT := 2024;
	PLANT_COMM_MONTH      : DINT := 8;
	PLANT_POI_LIMIT_MW    : REAL := 150.0;

	// Sensor counts: change these per site
	FRONT_SENSOR_COUNT    : INT := 4;
	REAR_SENSOR_COUNT     : INT := 4;
	BOM_SENSOR_COUNT      : INT := 12;
END_VAR

Content.Implementation:
// ============================================================
// IMPORT-SAFE TEMPLATE
// This implementation is intentionally commented to avoid import
// errors when site-specific tags are not present.
//
// Action required:
// 1) Uncomment this block.
// 2) Replace all placeholder/site example tags with your site tags.
// 3) Keep all site-specific mapping changes in this file only.
// ============================================================
(*
// ============================================================
// SECTION 1: Map site tags to front POA sensors
// ============================================================
FrontPOA[1].Quality := Tags.SITE_DMET1_IRRAD_FPOA.status.q.validity;
FrontPOA[1].Value   := Tags.SITE_DMET1_IRRAD_FPOA.status.instMag;
FrontPOA[2].Quality := Tags.SITE_DMET2_IRRAD_FPOA.status.q.validity;
FrontPOA[2].Value   := Tags.SITE_DMET2_IRRAD_FPOA.status.instMag;
FrontPOA[3].Quality := Tags.SITE_DMET3_IRRAD_FPOA.status.q.validity;
FrontPOA[3].Value   := Tags.SITE_DMET3_IRRAD_FPOA.status.instMag;
FrontPOA[4].Quality := Tags.SITE_DMET4_IRRAD_FPOA.status.q.validity;
FrontPOA[4].Value   := Tags.SITE_DMET4_IRRAD_FPOA.status.instMag;

// ============================================================
// SECTION 2: Map site tags to rear POA sensors
// ============================================================
RearPOA[1].Quality  := Tags.SITE_DMET1_IRRAD_RPOA.status.q.validity;
RearPOA[1].Value    := Tags.SITE_DMET1_IRRAD_RPOA.status.instMag;
RearPOA[2].Quality  := Tags.SITE_DMET2_IRRAD_RPOA.status.q.validity;
RearPOA[2].Value    := Tags.SITE_DMET2_IRRAD_RPOA.status.instMag;
RearPOA[3].Quality  := Tags.SITE_DMET3_IRRAD_RPOA.status.q.validity;
RearPOA[3].Value    := Tags.SITE_DMET3_IRRAD_RPOA.status.instMag;
RearPOA[4].Quality  := Tags.SITE_DMET4_IRRAD_RPOA.status.q.validity;
RearPOA[4].Value    := Tags.SITE_DMET4_IRRAD_RPOA.status.instMag;

// ============================================================
// SECTION 3: Map site tags to BOM temperature sensors
// ============================================================
BOMTemp[1].Quality  := SITE_DMET1_BOM_TEMP_1.status.q.validity;
BOMTemp[1].Value    := SITE_DMET1_BOM_TEMP_1.status.instMag;
BOMTemp[2].Quality  := SITE_DMET1_BOM_TEMP_2.status.q.validity;
BOMTemp[2].Value    := SITE_DMET1_BOM_TEMP_2.status.instMag;
BOMTemp[3].Quality  := SITE_DMET1_BOM_TEMP_3.status.q.validity;
BOMTemp[3].Value    := SITE_DMET1_BOM_TEMP_3.status.instMag;
BOMTemp[4].Quality  := SITE_DMET2_BOM_TEMP_1.status.q.validity;
BOMTemp[4].Value    := SITE_DMET2_BOM_TEMP_1.status.instMag;
BOMTemp[5].Quality  := SITE_DMET2_BOM_TEMP_2.status.q.validity;
BOMTemp[5].Value    := SITE_DMET2_BOM_TEMP_2.status.instMag;
BOMTemp[6].Quality  := SITE_DMET2_BOM_TEMP_3.status.q.validity;
BOMTemp[6].Value    := SITE_DMET2_BOM_TEMP_3.status.instMag;
BOMTemp[7].Quality  := SITE_DMET3_BOM_TEMP_1.status.q.validity;
BOMTemp[7].Value    := SITE_DMET3_BOM_TEMP_1.status.instMag;
BOMTemp[8].Quality  := SITE_DMET3_BOM_TEMP_2.status.q.validity;
BOMTemp[8].Value    := SITE_DMET3_BOM_TEMP_2.status.instMag;
BOMTemp[9].Quality  := SITE_DMET3_BOM_TEMP_3.status.q.validity;
BOMTemp[9].Value    := SITE_DMET3_BOM_TEMP_3.status.instMag;
BOMTemp[10].Quality := SITE_DMET4_BOM_TEMP_1.status.q.validity;
BOMTemp[10].Value   := SITE_DMET4_BOM_TEMP_1.status.instMag;
BOMTemp[11].Quality := SITE_DMET4_BOM_TEMP_2.status.q.validity;
BOMTemp[11].Value   := SITE_DMET4_BOM_TEMP_2.status.instMag;
BOMTemp[12].Quality := SITE_DMET4_BOM_TEMP_3.status.q.validity;
BOMTemp[12].Value   := SITE_DMET4_BOM_TEMP_3.status.instMag;

// ============================================================
// SECTION 4: Call generic RTPP function block
// Constants and tag mappings are the only site-specific parts.
// ============================================================
RTPP(
	// Inverter availability
	TotalInverters        := PLANT_TOTAL_INVERTERS,
	AvailableInverters    := Tags.SITE_PPC_INV_RUNNING_COUNT.instMag,

	// Sensors
	FrontPOASensors       := FrontPOA,
	NumberOfFPOASensors   := FRONT_SENSOR_COUNT,
	RearPOASensors        := RearPOA,
	NumberOfRPOASensors   := REAR_SENSOR_COUNT,
	BOMTempSensors        := BOMTemp,
	NumberOfBOMTempSensors:= BOM_SENSOR_COUNT,

	// Plant parameters
	DCPowerNominalMW      := PLANT_DC_NOMINAL_MW,
	commYear              := PLANT_COMM_YEAR,
	commMonth             := PLANT_COMM_MONTH,

	// Electrical parameters
	BifacialityFactor     := 0.70,
	TempCoef              := -0.0034,
	DegradationRate       := 0.005,
	DCLossesPercent       := 0.005,
	ACLossesPercent       := 0.015,
	InvEfficiency         := 0.98,
	PlantPOILimitMW       := PLANT_POI_LIMIT_MW,

	// Regression conditioning (site tags)
	// ActivePowerMW must be the PV generation meter in MW.
	ActivePowerMW         := SITE_PV_METER_KW_3PH.instMag * 0.001,
	PSetpointMW           := Tags.SITE_PPC_P_SP_RTU.oper.setMag,

	// Regression timer
	RegressionIntervalS   := T#60S
);

// ============================================================
// SECTION 5: Write generic outputs
// ============================================================
RTPP_OUTPUT.instMag := RTPP.RTPP_MW;
RTPP_OUTPUT.t       := System_Time_Control_POU.System_Time;
RTPP_OUTPUT.q       := GOOD_QUALITY;

HSL_OUTPUT.instMag  := RTPP.HSL_MW;
HSL_OUTPUT.t        := System_Time_Control_POU.System_Time;
HSL_OUTPUT.q        := GOOD_QUALITY;

// --- Diagnostics to globals (optional, useful for SCADA trending) ---
FRONT_POA_AVG          := RTPP.FrontPOA_Avg;
REAR_POA_AVG           := RTPP.RearPOA_Avg;
BOM_AVG                := RTPP.BOMTemp_Avg;
*)
